import{_ as s,a,o as t,P as e}from"./chunks/framework.C4T-_spZ.js";const g=JSON.parse('{"title":"搭建git服务器(linux)","description":"搭建git服务器(linux)","frontmatter":{"id":1751264797561,"date":"2025/07/01 15:52","title":"搭建git服务器(linux)","description":"搭建git服务器(linux)","tag":"Git","archive":null,"recommendations":{"recommendations":null},"shadow":false,"top":0},"headers":[],"relativePath":"BuildGitServer.md","filePath":"BuildGitServer.md"}'),l={name:"BuildGitServer.md"};function n(h,i,p,d,o,r){return t(),a("div",null,i[0]||(i[0]=[e(`<h1 id="搭建-git-服务器-linux" tabindex="-1">搭建 git 服务器(linux) <a class="header-anchor" href="#搭建-git-服务器-linux" aria-label="Permalink to &quot;搭建 git 服务器(linux)&quot;">​</a></h1><p>这里只要为个人使用的 git 仓库。</p><h2 id="安装-git" tabindex="-1">安装 git <a class="header-anchor" href="#安装-git" aria-label="Permalink to &quot;安装 git&quot;">​</a></h2><p>在 Ubuntu 上，可以通过以下命令安装 Git：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span></span></code></pre></div><p>安装完成后，运行以下命令检查 Git 版本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>如果显示了 Git 的版本号，说明安装成功。</p><h2 id="创建-git-裸仓库" tabindex="-1">创建 Git 裸仓库 <a class="header-anchor" href="#创建-git-裸仓库" aria-label="Permalink to &quot;创建 Git 裸仓库&quot;">​</a></h2><p>创建一个目录如 <code>/git/test.git</code>，并在文件夹下创建 git 裸仓库:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /git/test.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /git/test.git</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bare</span></span></code></pre></div><h2 id="连接-git-仓库" tabindex="-1">连接 Git 仓库 <a class="header-anchor" href="#连接-git-仓库" aria-label="Permalink to &quot;连接 Git 仓库&quot;">​</a></h2><p>到目前为止服务器仓库已经搭建完成，对应的 origin 地址为 <code>root@192.168.45.4:/git/test.git</code>。 根据自己的用户名，ip 地址和仓库地址进行修改。</p><h2 id="免密连接" tabindex="-1">免密连接 <a class="header-anchor" href="#免密连接" aria-label="Permalink to &quot;免密连接&quot;">​</a></h2><p>在添加了远程地址后，进行推送，拉取等操作时还需要输入密码。由于使用的 ssh 连接，可以通过密钥方式解决。</p><ol><li>运行命令生成密钥对：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keygen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rsa</span></span></code></pre></div><p>改命令会在 <code>C:\\Users\\dhn\\.ssh</code> 中生成两个文件：私钥 <code>id_rsa</code> 和公钥 <code>id_rsa.pub</code>。</p><ol start="2"><li>把 <code>id_rsa.pub</code> 文件内容复制到在服务器的 <code>/root/.ssh/authorized_keys</code> 文件中。文件内容为一行，复制过去为单独一行。</li></ol><p>设置完成后，在进行 git 操作将不再需要输入密码。</p>`,20)]))}const k=s(l,[["render",n]]);export{g as __pageData,k as default};
